function Get-DownloadUrl {
    param (
        [string]$fid,
        [string]$p = $null
    )
    try {
        $baseUrl = 'https://lanzoup.com'
        $response = Invoke-WebRequest -UseBasicParsing -Uri "$baseUrl/$fid" -Headers @{ 'User-Agent' = '' }
    }
